import React, { useState, useEffect } from 'react';
import { Link, useNavigate, useParams } from 'react-router-dom';
import { useAuth } from '../../context/AuthContext';
import { 
  GraduationCap, Users, Shield, Eye, EyeOff, Loader2, ArrowLeft,
  User, Mail, Lock, ArrowRight
} from 'lucide-react';

const LoginPage = () => {
  const navigate = useNavigate();
  const { portal: urlPortal } = useParams();
  const { unifiedLogin } = useAuth();

  const [showPassword, setShowPassword] = useState(false);
  const [loading, setLoading] = useState(false);
  const [formData, setFormData] = useState({
    identifier: '',
    password: ''
  });

  // Set portal from URL parameter (for backward compatibility)
  useEffect(() => {
    if (urlPortal && ['student', 'teacher', 'admin'].includes(urlPortal)) {
      // We can ignore this now since we have unified login
    }
  }, [urlPortal]);

  const getGradientClass = () => {
    return 'from-orange-600 via-orange-700 to-orange-900';
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    if (!formData.identifier || !formData.password) return;

    setLoading(true);
    try {
      const result = await unifiedLogin(formData.identifier, formData.password);
      if (result.success) {
        // Navigate based on detected role
        const userRole = result.user.role;
        switch (userRole) {
          case 'student':
            navigate('/student/dashboard');
            break;
          case 'teacher':
            navigate('/teacher/dashboard');
            break;
          case 'admin':
            navigate('/admin/dashboard');
            break;
          default:
            navigate('/dashboard'); // fallback
        }
      }
    } catch (error) {
      console.error('Login error:', error);
    } finally {
      setLoading(false);
    }
  };

  const handlePortalSelect = (portalId) => {
    setSelectedPortal(portalId);
    setFormData({ identifier: '', password: '' });
  };

  const handleBack = () => {
    setSelectedPortal(null);
    setFormData({ identifier: '', password: '' });
  };

  return (
    <div className={`min-h-screen bg-gradient-to-br ${getGradientClass()} flex items-center justify-center p-6 relative overflow-hidden transition-all duration-500`}>
      {/* Background decoration */}
      <div className="absolute inset-0 overflow-hidden">
        <div className="absolute -top-20 -right-20 w-60 h-60 bg-black/10 rounded-full blur-3xl"></div>
        <div className="absolute bottom-20 -left-20 w-40 h-40 bg-black/5 rounded-full blur-2xl"></div>
        <div className="absolute top-1/2 right-1/4 w-32 h-32 bg-black/5 rounded-full blur-xl"></div>
      </div>

      <div className="w-full max-w-md relative z-10">
        {/* Back Link */}
        <div className="flex items-center justify-between mb-8">
          <Link to="/" className="inline-flex items-center gap-2 text-white/80 hover:text-white transition-colors group">
            <ArrowLeft className="w-4 h-4 group-hover:-translate-x-1 transition-transform" />
            Back to Home
          </Link>
        </div>

        {/* Login Card */}
        <div className="bg-black rounded-2xl shadow-2xl overflow-hidden animate-scale-in border border-orange-500/20">
          {/* Login Form */}
          <div className="p-8">
            {/* Header */}
            <div className="text-center mb-8">
              <div className="w-20 h-20 bg-gradient-to-br from-orange-400 to-orange-600 rounded-2xl flex items-center justify-center mx-auto mb-5 shadow-lg border border-orange-500/30">
                <GraduationCap className="w-10 h-10 text-white" />
              </div>
              <h1 className="text-2xl font-bold text-white">Welcome Back</h1>
              <p className="text-gray-300 mt-2">Enter your credentials to continue</p>
              <div className="mt-4 p-3 bg-orange-500/10 rounded-lg border border-orange-500/20">
                <p className="text-orange-300 text-sm">
                  <strong>Unified Login:</strong> Enter your Student ID, Email, or Username
                </p>
              </div>
            </div>

            {/* Form */}
            <form onSubmit={handleSubmit} className="space-y-5">
              <div>
                <label className="block text-sm font-medium text-gray-200 mb-2">Student ID / Email / Username</label>
                <div className="relative">
                  <User className="absolute left-3 top-1/2 -translate-y-1/2 w-5 h-5 text-gray-400" />
                  <input
                    type="text"
                    value={formData.identifier}
                    onChange={(e) => setFormData(prev => ({ ...prev, identifier: e.target.value }))}
                    className="w-full pl-10 pr-4 py-3 bg-gray-800/50 border border-gray-600 rounded-lg text-white placeholder-gray-400 focus:outline-none focus:border-orange-500 focus:ring-2 focus:ring-orange-500/20 transition-all"
                    placeholder="Enter your Student ID, Email, or Username"
                    required
                  />
                </div>
              </div>

              <div>
                <label className="block text-sm font-medium text-gray-200 mb-2">Password</label>
                <div className="relative">
                  <Lock className="absolute left-3 top-1/2 -translate-y-1/2 w-5 h-5 text-gray-400" />
                  <input
                    type={showPassword ? 'text' : 'password'}
                    value={formData.password}
                    onChange={(e) => setFormData(prev => ({ ...prev, password: e.target.value }))}
                    className="w-full pl-10 pr-12 py-3 bg-gray-800/50 border border-gray-600 rounded-lg text-white placeholder-gray-400 focus:outline-none focus:border-orange-500 focus:ring-2 focus:ring-orange-500/20 transition-all"
                    placeholder="Enter your password"
                    required
                  />
                  <button
                    type="button"
                    onClick={() => setShowPassword(!showPassword)}
                    className="absolute right-3 top-1/2 -translate-y-1/2 text-gray-400 hover:text-orange-400 transition-colors"
                  >
                    {showPassword ? <EyeOff className="w-5 h-5" /> : <Eye className="w-5 h-5" />}
                  </button>
                </div>
              </div>

              <button
                type="submit"
                disabled={loading}
                className="w-full py-3 flex items-center justify-center gap-2 font-medium rounded-lg transition-all duration-200 shadow-sm hover:shadow-md bg-gradient-to-r from-orange-500 to-orange-600 hover:from-orange-600 hover:to-orange-700 text-black font-semibold disabled:opacity-50 disabled:cursor-not-allowed border border-orange-400/30"
              >
                {loading ? (
                  <>
                    <Loader2 className="w-5 h-5 animate-spin" />
                    Authenticating...
                  </>
                ) : (
                  <>
                    <Lock className="w-4 h-4" />
                    Login
                  </>
                )}
              </button>
            </form>

            {/* Footer */}
            <div className="mt-6 text-center">
              <p className="text-gray-400 text-sm">
                Forgot your password? <span className="text-orange-400 font-medium hover:text-orange-300 transition-colors">Contact administrator</span>
              </p>
            </div>

            {/* Default credentials hint */}
            <div className="mt-4 p-4 bg-orange-500/10 rounded-xl border border-orange-500/20">
              <p className="text-orange-300 text-sm text-center">
                <strong>Default Admin Credentials:</strong> admin / admin123
              </p>
              <p className="text-orange-400 text-xs text-center mt-1">
                Students: Use your Student ID | Teachers: Use your Email
              </p>
            </div>
          </div>
        </div>

        {/* Footer */}
        <div className="mt-6 text-center">
          <p className="text-white/60 text-sm">
            © 2024 CCS Management System
          </p>
        </div>
      </div>
    </div>
  );
};

export default LoginPage;
